class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.size();
        vector<int> last(26, -1);
        for (int i = 0; i < n; ++i) {
            int c = word[i] - 'a';
            last[c] = i;
        }
        int res = 0;
        int end = -1;
        for (int i = 0; i < n; ++i) {
            int c = word[i] - 'a';
            int j = last[c];
            if (j - i + 1 >= 4 && j > end) {
                ++res;
                end = j;
            }
        }
        return res;
    }
};
```
